import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { Plus, Search, Filter, Calendar, Tag, Trash2, X, Save, User } from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';
import '../styles/Despesas.css';

const Despesas = () => {
  const [despesas, setDespesas] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [responsaveis, setResponsaveis] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [itemEditando, setItemEditando] = useState(null);
  const navigate = useNavigate();

  // Estado para o Modal de Feedback
  const [feedback, setFeedback] = useState({
    isOpen: false,
    type: 'success',
    title: '',
    message: '',
    onConfirm: null
  });

  useEffect(() => {
    buscarDados();
  }, []);

  const alertar = (type, title, message, onConfirm = null) => {
    setFeedback({ isOpen: true, type, title, message, onConfirm });
  };

  async function buscarDados() {
    setLoading(true);
    try {
      // 1. Buscar Despesas
      const { data, error } = await supabase
        .from('compras')
        .select(`*, categorias (nome, cor)`)
        .eq('tipo_despesa', 'Gastos Variáveis')
        .order('data_compra', { ascending: false });

      // 2. Buscar Categorias em Ordem Alfabética
      const { data: dataCat } = await supabase
        .from('categorias')
        .select('*')
        .order('nome', { ascending: true });

      // 3. Buscar Responsáveis (Profiles) em Ordem Alfabética
      const { data: dataProf } = await supabase
        .from('profiles')
        .select('id, nome')
        .order('nome', { ascending: true });

      if (error) throw error;
      setDespesas(data || []);
      setCategorias(dataCat || []);
      setResponsaveis(dataProf || []);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setLoading(false);
    }
  }

  const formatarMoeda = (valor) => {
    return Number(valor).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  const handleMascaraMoeda = (e) => {
    let valor = e.target.value.replace(/\D/g, "");
    const valorNumerico = (Number(valor) / 100).toFixed(2);
    const valorFormatado = new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(valorNumerico);
    setItemEditando({ ...itemEditando, valor_exibicao: valorFormatado });
  };

  const handleAbrirModal = (item) => {
    const valorInicial = formatarMoeda(item.valor_total);
    // Aqui garantimos que o responsavel_id seja carregado do item vindo do banco
    setItemEditando({ 
      ...item, 
      valor_exibicao: valorInicial,
      responsavel_id: item.user_id || '' 
    });
    setIsModalOpen(true);
  };

  const handleSalvarEdicao = async (e) => {
    e.preventDefault();
    try {
      const valorLimpo = Number(itemEditando.valor_exibicao.replace(/[^\d,]/g, '').replace(',', '.'));
      const { error } = await supabase
        .from('compras')
        .update({
          descricao: itemEditando.descricao,
          valor_total: valorLimpo,
          data_compra: itemEditando.data_compra,
          categoria_id: itemEditando.categoria_id,
          responsavel_id: itemEditando.responsavel_id // Salva o responsável selecionado
        })
        .eq('id', itemEditando.id);

      if (error) throw error;
      setIsModalOpen(false);
      buscarDados();
      alertar('success', 'Sucesso!', 'Alterações guardadas com sucesso.');
    } catch (error) {
      alertar('error', 'Erro ao salvar', error.message);
    }
  };

  const handleExcluir = () => {
    alertar('danger', 'Excluir Despesa?', `Deseja apagar "${itemEditando.descricao}"?`, async () => {
      const { error } = await supabase.from('compras').delete().eq('id', itemEditando.id);
      if (!error) {
        setIsModalOpen(false);
        setFeedback({ ...feedback, isOpen: false });
        buscarDados();
      } else {
        alertar('error', 'Erro ao excluir', error.message);
      }
    });
  };

  const filteredDespesas = despesas.filter(d => 
    d.descricao.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <>
      <div className="desp-premium-wrapper">
        <div className="desp-top-layout">
          <header className="desp-panel desp-header-area">
            <div className="desp-title-area">
              <h1>Despesas</h1>
              <p>Pagamentos à vista e variáveis</p>
            </div>
            <div className="desp-search-box">
              <Search size={18} color="#94a3b8" />
              <input 
                type="text" 
                placeholder="Pesquisar..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </header>
          <div className="desp-panel desp-summary-card">
            <span className="summary-label">Total do Período</span>
            <h2 className="summary-value">
              {formatarMoeda(filteredDespesas.reduce((acc, curr) => acc + Number(curr.valor_total), 0))}
            </h2>
          </div>
        </div>

        <main className="desp-panel desp-list-panel">
          <div className="list-header">
            <h3 style={{fontWeight: 800, color: '#475569', margin: 0}}>Movimentações</h3>
            <Filter size={18} color="#94a3b8" />
          </div>

          <div className="desp-list">
            {loading ? (
              <div style={{padding: '40px', textAlign: 'center'}}>Carregando...</div>
            ) : filteredDespesas.map((item) => (
              <div key={item.id} className="desp-item-row" onClick={() => handleAbrirModal(item)}>
                <div className="desp-left-content">
                  <div className="cat-indicator" style={{ backgroundColor: item.categorias?.cor || '#ccc' }}></div>
                  <div className="desp-details">
                    <span className="desp-desc">{item.descricao}</span>
                    <div className="desp-meta">
                      <span className="meta-tag">
                        <Calendar size={12} /> 
                        {new Date(item.data_compra).toLocaleDateString('pt-BR', {timeZone: 'UTC'})}
                      </span>
                      <span className="meta-tag">
                        <Tag size={12} /> 
                        {item.categorias?.nome}
                      </span>
                      {/* Badge do Responsável na Lista */}
                      {responsaveis.find(r => r.id === item.responsavel_id) && (
                         <span className="meta-tag">
                           <User size={12} /> {responsaveis.find(r => r.id === item.responsavel_id)?.nome}
                         </span>
                      )}
                    </div>
                  </div>
                </div>
                <span className="desp-value">{formatarMoeda(item.valor_total)}</span>
              </div>
            ))}
          </div>
        </main>

        {isModalOpen && itemEditando && (
          <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
            <div className="edit-modal" onClick={e => e.stopPropagation()}>
              <div className="modal-header-flex">
                <h2 style={{margin: 0, fontWeight: 900, color: '#0f172a'}}>Detalhes</h2>
                <button onClick={() => setIsModalOpen(false)} className="close-btn-desp">
                  <X size={20} color="#64748b" />
                </button>
              </div>

              <form onSubmit={handleSalvarEdicao} className="edit-form-grid">
                <div className="form-group">
                  <label>O QUE FOI COMPRADO?</label>
                  <input 
                    type="text" 
                    value={itemEditando.descricao} 
                    onChange={e => setItemEditando({...itemEditando, descricao: e.target.value})} 
                    required 
                  />
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label>VALOR</label>
                    <input type="text" value={itemEditando.valor_exibicao} onChange={handleMascaraMoeda} required />
                  </div>
                  <div className="form-group">
                    <label>DATA</label>
                    <input 
                      type="date" 
                      value={itemEditando.data_compra} 
                      onChange={e => setItemEditando({...itemEditando, data_compra: e.target.value})} 
                      required 
                    />
                  </div>
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label>CATEGORIA</label>
                    <select 
                      value={itemEditando.categoria_id} 
                      onChange={e => setItemEditando({...itemEditando, categoria_id: e.target.value})}
                    >
                      {categorias.map(cat => (
                        <option key={cat.id} value={cat.id}>{cat.nome}</option>
                      ))}
                    </select>
                  </div>
                  
                  {/* SELECT RESPONSÁVEL EM ORDEM ALFABÉTICA */}
                  <div className="form-group">
                    <label>RESPONSÁVEL</label>
                    <select 
                      value={itemEditando.responsavel_id} 
                      onChange={e => setItemEditando({...itemEditando, responsavel_id: e.target.value})} 
                      required
                    >
                      <option value="">Selecione...</option>
                      {responsaveis.map(resp => (
                        <option key={resp.id} value={resp.id}>{resp.nome}</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="modal-footer-actions">
                  <button type="submit" className="btn-save-full">
                    <Save size={18} /> Salvar Alterações
                  </button>
                  <button type="button" className="btn-delete-full" onClick={handleExcluir}>
                    <Trash2 size={18} /> Excluir
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>

      <ModalFeedback 
        isOpen={feedback.isOpen}
        type={feedback.type}
        title={feedback.title}
        message={feedback.message}
        onClose={() => setFeedback({ ...feedback, isOpen: false })}
        onConfirm={feedback.onConfirm}
      />
      
      <button className="desp-fab" onClick={() => navigate('/lancamento')}>
        <Plus size={30} />
      </button>
    </>
  );
};

export default Despesas;
